class WriteFileTool(BaseTool):
    """A tool to write text to a file with safety checks."""    
    @property
    def name(self) -> str:
        return "write_file"

    @property
    def description(self) -> str:
        return "Write code, HTML, CSS or text to a file. USE THIS to build systems, pages and apps. Only writes to allowed directories."

    @property
    def arguments(self) -> Dict[str, str]:
        return {
            "path": "The destination file path (must be within allowed directories).",
            "content": "The string content to write."
        }

    def _is_safe_path(self, path: str) -> bool:
        """Check if path is within allowed directories."""
        base_dir = os.path.abspath(os.getcwd())
        requested_path = os.path.abspath(os.path.join(base_dir, path))
        return requested_path.startswith(base_dir)

    def execute(self, **kwargs) -> str:
        path = kwargs.get("path") or kwargs.get("file_path")
        content = kwargs.get("content", "")

        if not path:
            return "Error: Missing file path."

        if not isinstance(content, str):
            return "Error: Content must be a string."

        if not self._is_safe_path(path):
            return f"Error: Path '{path}' is not allowed."

        try:
            os.makedirs(os.path.dirname(path), exist_ok=True)
            with open(path, "w", encoding="utf-8") as f:
                f.write(content)
            logging.info(f"File written successfully: {path}")
            return f"Successfully wrote to {path}."
        except Exception as e:
            logging.error(f"Error writing file {path}: {str(e)}")
            return f"Error writing file: {str(e)}"


